mapper.update:
UPDATE accommodations
SET
    status = 'INACTIVE',
    updated_at = #{updatedAt}
WHERE accommodation_id = #{accommodationId}
  AND status = 'ACTIVE'

UPDATE room_types
SET
    status = 'INACTIVE',
    updated_at = #{updatedAt}
WHERE room_type_id = #{roomTypeId}
  AND status = 'ACTIVE'

UPDATE rooms
SET
    status = 'INACTIVE',
    updated_at = #{updatedAt}
WHERE room_id = #{roomId}
  AND status != 'INACTIVE'
